\begin{tikzpicture}[node distance=1.6cm]

  % Step 1: Wide Table
  \node[draw, rectangle, minimum width=5.8cm, minimum height=1.3cm, fill=white, align=center] (wide) at (0, 8) {
    \textbf{Step 1: Wide Table (Before)}\\
    {\small Product $|$ Q1\_2024 $|$ Q2\_2024 $|$ Q3\_2024 $|$ Q4\_2024}
  };

  % Arrow 1
  \draw[->, line width=1.5pt] (wide.south) -- (0, 6.5);
  \node[right, font=\small\bfseries, color=blue!70!black] at (0.2, 7.2) {Unpivot Columns};

  % Step 2: Unpivoted
  \node[draw, rectangle, minimum width=5.8cm, minimum height=1.3cm, fill=white, align=center] (unpiv) at (0, 5.8) {
    \textbf{Step 2: After Unpivot}\\
    {\small Product $|$ Attribute $|$ Value}\\
    {\small Widget A $|$ Q1\_2024 $|$ 18750}
  };

  % Arrow 2
  \draw[->, line width=1.5pt] (unpiv.south) -- (0, 4.3);
  \node[right, font=\small\bfseries, color=blue!70!black] at (0.2, 5.1) {Split Column by \_};

  % Step 3: Split
  \node[draw, rectangle, minimum width=5.8cm, minimum height=1.3cm, fill=white, align=center] (split) at (0, 3.6) {
    \textbf{Step 3: After Split}\\
    {\small Product $|$ Quarter $|$ Year $|$ Revenue}\\
    {\small Widget A $|$ Q1 $|$ 2024 $|$ 18750}
  };

  % Arrow 3
  \draw[->, line width=1.5pt] (split.south) -- (0, 2.1);
  \node[right, font=\small\bfseries, color=blue!70!black] at (0.2, 2.9) {Change Year to Whole Number};

  % Step 4: Final
  \node[draw, rectangle, minimum width=5.8cm, minimum height=1.3cm, fill=white, align=center] (final) at (0, 1.4) {
    \textbf{Step 4: Normalized Fact Table}\\
    {\small Product $|$ Quarter (text) $|$ Year (int) $|$ Revenue}
  };

  % Date Dimension
  \node[draw, rectangle, minimum width=4.2cm, minimum height=1.1cm, fill=yellow!20, align=center] (dim) at (0, -0.4) {
